#include <bits/stdc++.h>
using namespace std;

struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(NULL) {}
};

int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];

    ListNode* head = new ListNode(nums[0]);
    ListNode* current = head;
    for(int i = 1; i < n; i++) {
        current->next = new ListNode(nums[i]);
        current = current->next;
    }

    ListNode* slow = head;
    ListNode* fast = head;
    stack<int> s;
    while(fast && fast->next) {
        s.push(slow->val);
        slow = slow->next;
        fast = fast->next->next;
    }
    if(fast) slow = slow->next;
    while(slow) {
        if(s.top() != slow->val) {
            cout << 0 << endl;
            return 0;
        }
        s.pop();
        slow = slow->next;
    }
    cout << 1 << endl;
    return 0;
}
